#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int n,a[N],t;
bool check(int x)
{
    int num=0;
    for(int i=1;i<=n;i++)
    {
        num+=a[i];
        if(num>x) return 0;
        if(num==x)
        {
            num=0;
        }
    }
    return 1;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>t;
    while(t--)
    {
        cin>>n;
        int sum=0,mx=0;
        for(int i=1;i<=n;i++)
        {
            cin>>a[i];
            sum+=a[i];
            mx=max(mx,a[i]);
        }
        if(sum==0)
        {
            cout<<"0\n";
            continue;
        }
        for(int i=mx;i<=sum;i++)
        {
            if(sum%i==0)
            {
                if(check(i))
                {
                    cout<<(n-sum/i)<<'\n';
                    break;
                }
            }
        }
    }
    return 0;
}
